/**
 * DeckCanvas - deck.gl-based canvas for semantic zoom visualization
 *
 * Replaces InfiniteCanvas (R3F-based) with deck.gl for:
 * - Native semantic zoom via CompositeLayer
 * - Built-in aggregation layers for heatmaps
 * - OrthographicView for non-geo timeline visualization
 * - Better bundle size and performance
 *
 * DECK-MIGRATE-001: Foundation component
 * DECK-MIGRATE-002: Layer implementations with LOD
 */

import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';
import type { PickingInfo } from '@deck.gl/core';
import type { Layer } from '@deck.gl/core';
import type { LODLevel } from '../data/types';
import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
import { getRenderData } from '../data/generator';
import { useCanvasSelector, canvasStore, canvasActions } from '../state';
import {
  createMacroLayers,
  createMesoLayers,
  createMicroLayers,
} from './layers';
import { useCanvasGestures } from './hooks/useCanvasGestures';
import { initializeSpatialIndex } from './spatial';

// ─────────────────────────────────────────────────────────────
// EXPORTED TYPES (matching InfiniteCanvas)
// ─────────────────────────────────────────────────────────────

/**
 * Viewport information passed to parent component
 */
export interface ViewportInfo {
  /** Y coordinate of the TOP of the viewport in world space */
  topY: number;
  /** Left edge of the viewport in world X coordinates */
  leftX: number;
  /** Right edge of the viewport in world X coordinates */
  rightX: number;
}

/**
 * Navigation target for programmatic navigation
 * Can specify trainIndex, dayOffset, or both
 */
export interface NavigationTarget {
  /** Train index (0-based) to center on vertically */
  trainIndex?: number;
  /** Day offset from start date to center on horizontally */
  dayOffset?: number;
  /** Optional zoom level to set (defaults to current zoom) */
  zoom?: number;
}

// ─────────────────────────────────────────────────────────────
// PROPS INTERFACE (matching InfiniteCanvas)
// ─────────────────────────────────────────────────────────────

export interface DeckCanvasProps {
  zoom: number;
  lod: LODLevel;
  onZoomChange: (zoom: number) => void;
  onViewportChange?: (viewport: ViewportInfo) => void;
  onMinZoomChange?: (minZoom: number) => void;
  animatedZoomTarget?: number | null;
  onAnimatedZoomComplete?: () => void;
  navigationTarget?: NavigationTarget | null;
  onNavigationComplete?: () => void;
  perfVisible?: boolean;
  perfEvent?: string;
}

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────

const { pxPerDay, pxPerTrain, maxZoom: configMaxZoom, lodThresholds } = DEFAULT_VIEW_CONFIG;

// Animation constants
const ZOOM_ANIMATION_DURATION = 250; // ms
const NAVIGATION_ANIMATION_DURATION = 300; // ms

// Data constants
const TRAIN_COUNT = 50;
const TOTAL_YEARS = 10;
const TOTAL_DAYS = TOTAL_YEARS * 365;

// LOD transition constants (hysteresis to prevent flickering)
const LOD_HYSTERESIS = 0.15; // 15% overlap zone for crossfade

// ─────────────────────────────────────────────────────────────
// ZOOM CONVERSIONS
// deck.gl uses log2 scale: zoom 0 = 1x, zoom 1 = 2x, zoom -1 = 0.5x
// ─────────────────────────────────────────────────────────────

function linearToDeckZoom(linearZoom: number): number {
  return Math.log2(linearZoom);
}

function deckToLinearZoom(deckZoom: number): number {
  return Math.pow(2, deckZoom);
}

// ─────────────────────────────────────────────────────────────
// DECK.GL VIEW STATE TYPE
// ─────────────────────────────────────────────────────────────

interface DeckViewState {
  target: [number, number];
  zoom: number;
  minZoom: number;
  maxZoom: number;
}

// ─────────────────────────────────────────────────────────────
// COMPONENT
// ─────────────────────────────────────────────────────────────

/**
 * DeckCanvas Component
 *
 * Main deck.gl canvas with OrthographicView for timeline visualization.
 * Compatible interface with InfiniteCanvas for seamless migration.
 */
export function DeckCanvas({
  zoom,
  lod: _lod,
  onZoomChange,
  onViewportChange,
  onMinZoomChange,
  animatedZoomTarget,
  onAnimatedZoomComplete,
  navigationTarget,
  onNavigationComplete,
  perfVisible: _perfVisible,
  perfEvent: _perfEvent,
}: DeckCanvasProps) {
  // Container ref for size tracking
  const containerRef = useRef<HTMLDivElement>(null);
  const [containerSize, setContainerSize] = useState({ width: 800, height: 600 });

  // Get render data and initialize spatial index
  const { tasks, spatialIndex } = useMemo(() => {
    const data = getRenderData();
    // Initialize spatial index for O(log n) viewport queries
    const index = initializeSpatialIndex(data.tasks);
    return { tasks: data.tasks, spatialIndex: index };
  }, []);

  // Calculate world bounds (trainCount, totalDays)
  const worldBounds = useMemo(
    () => calculateWorldBounds(TRAIN_COUNT, TOTAL_DAYS),
    []
  );

  // Calculate effective minimum zoom based on canvas size
  const effectiveMinZoom = useMemo(() => {
    const worldWidth = worldBounds.maxX - worldBounds.minX;
    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
    const zoomToFitWidth = containerSize.width / worldWidth;
    const zoomToFitHeight = containerSize.height / worldHeight;
    return Math.max(0.05, Math.min(zoomToFitWidth, zoomToFitHeight) * 0.9);
  }, [worldBounds, containerSize]);

  // Report effective min zoom to parent
  useEffect(() => {
    onMinZoomChange?.(effectiveMinZoom);
  }, [effectiveMinZoom, onMinZoomChange]);

  // Initialize deck.gl view state from props
  const [viewState, setViewState] = useState<DeckViewState>(() => ({
    target: [worldBounds.maxX / 4, worldBounds.minY / 4], // Start near top-left
    zoom: linearToDeckZoom(zoom),
    minZoom: linearToDeckZoom(effectiveMinZoom),
    maxZoom: linearToDeckZoom(configMaxZoom),
  }));

  // Sync external zoom changes to internal view state
  useEffect(() => {
    const newDeckZoom = linearToDeckZoom(zoom);
    if (Math.abs(viewState.zoom - newDeckZoom) > 0.01) {
      setViewState(prev => ({
        ...prev,
        zoom: newDeckZoom,
      }));
    }
  }, [zoom]);

  // Update min zoom when effective min changes
  useEffect(() => {
    setViewState(prev => ({
      ...prev,
      minZoom: linearToDeckZoom(effectiveMinZoom),
    }));
  }, [effectiveMinZoom]);

  // Handle animated zoom target
  useEffect(() => {
    if (animatedZoomTarget != null) {
      const targetDeckZoom = linearToDeckZoom(animatedZoomTarget);
      setViewState(prev => ({
        ...prev,
        zoom: targetDeckZoom,
      }));
      // Report completion after animation duration
      const timeout = setTimeout(() => {
        onAnimatedZoomComplete?.();
      }, ZOOM_ANIMATION_DURATION);
      return () => clearTimeout(timeout);
    }
  }, [animatedZoomTarget, onAnimatedZoomComplete]);

  // Handle navigation target
  useEffect(() => {
    if (navigationTarget) {
      const newTarget: [number, number] = [...viewState.target];

      if (navigationTarget.dayOffset !== undefined) {
        newTarget[0] = navigationTarget.dayOffset * pxPerDay;
      }
      if (navigationTarget.trainIndex !== undefined) {
        // Y is negative (trains go down)
        newTarget[1] = -navigationTarget.trainIndex * pxPerTrain - pxPerTrain / 2;
      }

      setViewState(prev => ({
        ...prev,
        target: newTarget,
        zoom: navigationTarget.zoom !== undefined
          ? linearToDeckZoom(navigationTarget.zoom)
          : prev.zoom,
      }));

      // Report completion
      const timeout = setTimeout(() => {
        onNavigationComplete?.();
      }, NAVIGATION_ANIMATION_DURATION);
      return () => clearTimeout(timeout);
    }
  }, [navigationTarget, onNavigationComplete]);

  // Track container size with ResizeObserver
  useEffect(() => {
    if (!containerRef.current) return;

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const { width, height } = entry.contentRect;
        setContainerSize({ width, height });
        // Also update toolkit store
        canvasStore.dispatch(canvasActions.viewport.setCanvasSize({ width, height }));
      }
    });

    observer.observe(containerRef.current);
    return () => observer.disconnect();
  }, []);

  // Get interaction state from @mms/toolkit
  const hoveredTaskId = useCanvasSelector(s => s.interaction.hoveredTaskId);
  const selectedTaskId = useCanvasSelector(s => s.interaction.selectedTaskId);

  // Handle view state changes from deck.gl controller
  const handleViewStateChange = useCallback(
    ({ viewState: newViewState }: { viewState: DeckViewState }) => {
      setViewState(newViewState);

      // Convert deck.gl zoom to linear and notify parent
      const linearZoom = deckToLinearZoom(newViewState.zoom);
      onZoomChange(linearZoom);

      // Calculate viewport info for parent
      const halfWidth = containerSize.width / linearZoom / 2;
      const halfHeight = containerSize.height / linearZoom / 2;

      const viewportInfo: ViewportInfo = {
        topY: newViewState.target[1] + halfHeight, // Top edge in world Y
        leftX: newViewState.target[0] - halfWidth,
        rightX: newViewState.target[0] + halfWidth,
      };
      onViewportChange?.(viewportInfo);

      // Update @mms/toolkit state for sidebar/timeline sync
      canvasStore.dispatch(
        canvasActions.viewport.setCamera({
          x: newViewState.target[0],
          y: newViewState.target[1],
        })
      );
    },
    [onZoomChange, onViewportChange, containerSize]
  );

  // Handle hover on tasks
  const handleHover = useCallback((info: PickingInfo) => {
    if (info.object && 'id' in info.object) {
      canvasStore.dispatch(canvasActions.interaction.setHoveredTask(info.object.id as string));
    } else {
      canvasStore.dispatch(canvasActions.interaction.clearHover(null));
    }
  }, []);

  // Handle click on tasks
  const handleClick = useCallback((info: PickingInfo) => {
    if (info.object && 'id' in info.object) {
      const taskId = info.object.id as string;
      const currentSelected = canvasStore.getState().interaction.selectedTaskId;
      if (currentSelected === taskId) {
        // Toggle off if clicking same task
        canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
      } else {
        canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
      }
    } else {
      // Click on background clears selection
      canvasStore.dispatch(canvasActions.interaction.clearSelection(null));
    }
  }, []);

  // ─────────────────────────────────────────────────────────────
  // GESTURE HANDLING (@use-gesture/react) - DECK-COMPLETE-002
  // ─────────────────────────────────────────────────────────────

  // Handle zoom from gestures (pinch, wheel)
  const handleGestureZoom = useCallback(
    (newZoom: number, cursorX?: number, cursorY?: number) => {
      const currentLinear = deckToLinearZoom(viewState.zoom);

      // If cursor position provided, zoom toward that point
      if (cursorX !== undefined && cursorY !== undefined) {
        // Convert cursor to world coordinates
        const zoomRatio = newZoom / currentLinear;

        // Calculate new target to zoom toward cursor
        const newTarget: [number, number] = [
          viewState.target[0] + (cursorX - containerSize.width / 2) / currentLinear * (1 - 1 / zoomRatio),
          viewState.target[1] + (cursorY - containerSize.height / 2) / currentLinear * (1 - 1 / zoomRatio),
        ];

        setViewState(prev => ({
          ...prev,
          target: newTarget,
          zoom: linearToDeckZoom(newZoom),
        }));
      } else {
        setViewState(prev => ({
          ...prev,
          zoom: linearToDeckZoom(newZoom),
        }));
      }
      // Note: onZoomChange is called via useEffect when viewState.zoom changes
    },
    [viewState, containerSize]
  );

  // Handle pan from gestures (drag, trackpad scroll)
  const handleGesturePan = useCallback(
    (deltaX: number, deltaY: number) => {
      const currentLinear = deckToLinearZoom(viewState.zoom);

      // Convert screen delta to world delta
      const worldDeltaX = deltaX / currentLinear;
      const worldDeltaY = deltaY / currentLinear;

      setViewState(prev => ({
        ...prev,
        target: [
          prev.target[0] - worldDeltaX,
          prev.target[1] - worldDeltaY,
        ],
      }));
    },
    [viewState.zoom]
  );

  // Sync viewState changes to parent and toolkit store
  useEffect(() => {
    const linearZoom = deckToLinearZoom(viewState.zoom);

    // Notify parent of zoom change
    onZoomChange(linearZoom);

    // Calculate viewport info
    const halfWidth = containerSize.width / linearZoom / 2;
    const halfHeight = containerSize.height / linearZoom / 2;

    const viewportInfo: ViewportInfo = {
      topY: viewState.target[1] + halfHeight,
      leftX: viewState.target[0] - halfWidth,
      rightX: viewState.target[0] + halfWidth,
    };
    onViewportChange?.(viewportInfo);

    // Update @mms/toolkit state
    canvasStore.dispatch(
      canvasActions.viewport.setCamera({
        x: viewState.target[0],
        y: viewState.target[1],
      })
    );
  }, [viewState.target, viewState.zoom, containerSize, onZoomChange, onViewportChange]);

  // Initialize gesture hook - returns bind function to spread on container
  const gestureBind = useCanvasGestures(
    {
      onZoom: handleGestureZoom,
      onPan: handleGesturePan,
    },
    {
      zoom: deckToLinearZoom(viewState.zoom),
      minZoom: effectiveMinZoom,
      maxZoom: configMaxZoom,
    }
  );

  // Calculate LOD level from zoom (for debug display)
  const currentLinearZoom = deckToLinearZoom(viewState.zoom);
  const lodLevel = currentLinearZoom < 0.5 ? 'MACRO' : currentLinearZoom > 2.0 ? 'MICRO' : 'MESO';

  // Calculate viewport bounds for culling
  const viewportBounds = useMemo(() => {
    const halfWidth = containerSize.width / currentLinearZoom / 2;
    const halfHeight = containerSize.height / currentLinearZoom / 2;
    return {
      minX: viewState.target[0] - halfWidth,
      maxX: viewState.target[0] + halfWidth,
      minY: viewState.target[1] - halfHeight,
      maxY: viewState.target[1] + halfHeight,
    };
  }, [viewState.target, currentLinearZoom, containerSize]);

  // Calculate LOD opacities for smooth crossfade transitions
  const lodOpacities = useMemo(() => {
    const z = currentLinearZoom;
    const { macro: macroThreshold, micro: microThreshold } = lodThresholds;
    const h = LOD_HYSTERESIS;

    // Macro: Full below 0.5, fade out 0.35-0.5
    const macroOpacity = z < macroThreshold - h
      ? 1
      : z > macroThreshold
        ? 0
        : 1 - (z - (macroThreshold - h)) / h;

    // Micro: Full above 2.0, fade in 1.85-2.0
    const microOpacity = z > microThreshold + h
      ? 1
      : z < microThreshold
        ? 0
        : (z - microThreshold) / h;

    // Meso: Full in the middle, fade at boundaries
    const mesoOpacity = Math.min(
      z >= macroThreshold - h ? 1 : 0, // Fade in with macro fade out
      z <= microThreshold + h ? 1 : 0   // Fade out with micro fade in
    );

    return {
      macro: Math.max(0, Math.min(1, macroOpacity)),
      meso: Math.max(0, Math.min(1, mesoOpacity)),
      micro: Math.max(0, Math.min(1, microOpacity)),
    };
  }, [currentLinearZoom]);

  // Create the OrthographicView
  // DECK-COMPLETE-002: Disable deck.gl controller, use @use-gesture/react instead
  const views = useMemo(() => new OrthographicView({
    id: 'timeline',
    flipY: false,
    controller: {
      scrollZoom: false,   // Handled by @use-gesture onWheel/onPinch
      dragPan: false,      // Handled by @use-gesture onDrag
      doubleClickZoom: true, // Keep for convenience
      touchRotate: false,
      keyboard: true,       // Keep arrow key navigation
    },
  }), []);

  // Get focused task ID from state
  const focusedTaskId = useCanvasSelector(s => s.interaction.focusedTaskId);

  // DECK-COMPLETE-003: Query visible tasks using spatial index
  const visibleTasks = useMemo(() => {
    // For MACRO level, use all tasks (heatmap needs full data)
    if (lodOpacities.macro > 0.5) {
      return tasks;
    }
    // For MESO/MICRO, use spatial index for viewport culling
    return spatialIndex.getVisibleTasks(viewportBounds, 200); // 200px overscan
  }, [spatialIndex, viewportBounds, lodOpacities.macro, tasks]);

  // Create layers based on LOD level with crossfade
  const layers = useMemo((): Layer[] => {
    const allLayers: Layer[] = [];

    // MacroLayer - visible when zoom < 0.5
    if (lodOpacities.macro > 0) {
      allLayers.push(
        ...createMacroLayers({
          tasks,
          trainCount: TRAIN_COUNT,
          totalYears: TOTAL_YEARS,
          visible: true,
          opacity: lodOpacities.macro,
        })
      );
    }

    // MesoLayer - visible when 0.5 <= zoom <= 2.0
    // Uses visibleTasks from spatial index for viewport culling
    if (lodOpacities.meso > 0) {
      allLayers.push(
        ...createMesoLayers({
          tasks: visibleTasks,
          trainCount: TRAIN_COUNT,
          totalDays: TOTAL_DAYS,
          visible: true,
          opacity: lodOpacities.meso,
          hoveredTaskId,
          selectedTaskId,
          focusedTaskId,
        })
      );
    }

    // MicroLayer - visible when zoom > 2.0
    // Uses visibleTasks from spatial index for viewport culling
    if (lodOpacities.micro > 0) {
      allLayers.push(
        ...createMicroLayers({
          tasks: visibleTasks,
          trainCount: TRAIN_COUNT,
          totalDays: TOTAL_DAYS,
          visible: true,
          opacity: lodOpacities.micro,
          linearZoom: currentLinearZoom,
          viewportBounds,
          hoveredTaskId,
          selectedTaskId,
          focusedTaskId,
        })
      );
    }

    return allLayers;
  }, [
    tasks,
    visibleTasks, // DECK-COMPLETE-003: Add visible tasks from spatial index
    lodOpacities,
    currentLinearZoom,
    viewportBounds,
    hoveredTaskId,
    selectedTaskId,
    focusedTaskId,
  ]);

  return (
    <div
      ref={containerRef}
      {...gestureBind()}
      style={{
        width: '100%',
        height: '100%',
        position: 'relative',
        background: '#f4f4f5', // zinc-100, matching original
        touchAction: 'none', // DECK-COMPLETE-002: Required for @use-gesture
      }}
    >
      <DeckGL
        views={views}
        viewState={viewState}
        onViewStateChange={handleViewStateChange as any}
        controller={true}
        layers={layers}
        onHover={handleHover}
        onClick={handleClick}
        width="100%"
        height="100%"
        style={{ position: 'absolute', top: '0', left: '0' }}
        getCursor={({ isDragging, isHovering }) =>
          isDragging ? 'grabbing' : isHovering ? 'pointer' : 'grab'
        }
      />

      {/* Debug overlay - shows deck.gl status */}
      <div
        style={{
          position: 'absolute',
          bottom: 8,
          right: 8,
          background: 'rgba(0,0,0,0.75)',
          color: '#00ff00',
          padding: '6px 10px',
          borderRadius: 4,
          fontSize: 11,
          fontFamily: 'monospace',
          pointerEvents: 'none',
          display: 'flex',
          flexDirection: 'column',
          gap: 2,
        }}
      >
        <div>deck.gl | LOD: {lodLevel} | Zoom: {currentLinearZoom.toFixed(2)}x</div>
        <div style={{ fontSize: 10, color: '#888' }}>
          Target: [{viewState.target[0].toFixed(0)}, {viewState.target[1].toFixed(0)}]
        </div>
      </div>
    </div>
  );
}

export default DeckCanvas;

