import { useState, useCallback, useEffect, useRef, useMemo } from 'react';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  ButtonGroup,
  Tag,
  Card,
  Intent,
  Alignment,
  OverlayToaster,
  Position,
} from '@blueprintjs/core';
import type { Toaster } from '@blueprintjs/core';
import { DeckCanvas } from './deck/DeckCanvas';
import type { ViewportInfo, NavigationTarget } from './deck/DeckCanvas';
import { TimelineHeader } from './components/TimelineHeader';
import { TaskTooltip } from './components/TaskTooltip';
import { TaskDetailsPanel } from './components/TaskDetailsPanel';
import { Minimap } from './components/Minimap';
import { usePerfMonitorToggle } from './components/PerfMonitor';
import type { PerfEvent } from './components/PerfMonitor';
import { PerformancePanel } from './components/StatsMonitor';
import { useCanvasSelector } from './state';
import { DEFAULT_VIEW_CONFIG } from './data/types';
import { getRenderData } from './data/generator';

type LOD = 'MACRO' | 'MESO' | 'MICRO';

// Number of trains to display in sidebar
const TRAIN_COUNT = 50;
const TOTAL_DAYS = 365 * 10; // 10 years
const { pxPerTrain, pxPerDay } = DEFAULT_VIEW_CONFIG;

// Sidebar width constant - used for TimelineHeader offset
const SIDEBAR_WIDTH = 130;

function App() {
  const [zoom, setZoom] = useState(1.0);
  // Dynamic min zoom calculated by DeckCanvas based on world bounds
  const [minZoom, setMinZoom] = useState(0.1);
  // viewportTopY: the Y coordinate of the TOP of the viewport in world space
  // 0 = top of TRAIN-001, -24 = top of TRAIN-002, etc.
  const [viewportTopY, setViewportTopY] = useState(0);
  // Viewport X bounds for timeline header
  const [viewportLeftX, setViewportLeftX] = useState(0);
  const [viewportRightX, setViewportRightX] = useState(1000);

  // Animated zoom target (for smooth button zoom)
  const [animatedZoomTarget, setAnimatedZoomTarget] = useState<number | null>(null);

  // Navigation target for sidebar/timeline clicks (F124)
  const [navigationTarget, setNavigationTarget] = useState<NavigationTarget | null>(null);

  // Performance monitor toggle (PERF-001)
  const { visible: perfVisible, toggle: togglePerf } = usePerfMonitorToggle(
    process.env.NODE_ENV === 'development'
  );

  // Performance event tracking for logging context
  const [isPanning, setIsPanning] = useState(false);
  const [isZooming, setIsZooming] = useState(false);
  const prevLod = useRef<LOD>('MESO');

  // Mouse position for tooltip (F020)
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });

  // BUG-004: Removed minimapVisible state - minimap is now always visible (Google Maps style)

  // Get hovered task ID from canvas state (F020)
  const hoveredTaskId = useCanvasSelector((s) => s.interaction.hoveredTaskId);

  // Get camera position from canvas state for minimap (F025)
  const canvasCameraX = useCanvasSelector((s) => s.viewport.camera.x);
  const canvasCameraY = useCanvasSelector((s) => s.viewport.camera.y);
  const canvasSizeFromStore = useCanvasSelector((s) => s.viewport.canvasSize);

  // Get render data for minimap (F025)
  const { tasks } = useMemo(() => getRenderData(), []);

  // Instructions toaster ref
  const toasterRef = useRef<Toaster | null>(null);

  // Show instructions on first load
  useEffect(() => {
    let isMounted = true;

    // Create toaster instance (async in BlueprintJS 6)
    OverlayToaster.createAsync({
      position: Position.TOP,
      className: 'instructions-toaster',
    }).then((toaster) => {
      if (!isMounted) return;
      toasterRef.current = toaster;

      // Show instruction toast with 5 second auto-dismiss
      toaster.show({
        message: '🖱️ Scroll to zoom  •  Drag to pan  •  Double-click to zoom in',
        intent: Intent.PRIMARY,
        timeout: 5000,
        icon: 'info-sign',
      });
    });

    // Cleanup: clear toaster on unmount
    return () => {
      isMounted = false;
      toasterRef.current?.clear();
    };
  }, []);

  // Compute LOD from zoom level
  const getLOD = (z: number): LOD => {
    if (z < 0.5) return 'MACRO';
    if (z > 2.0) return 'MICRO';
    return 'MESO';
  };

  const lod = getLOD(zoom);

  const getLODIntent = (l: LOD): Intent => {
    switch (l) {
      case 'MACRO': return Intent.WARNING;
      case 'MESO': return Intent.PRIMARY;
      case 'MICRO': return Intent.SUCCESS;
    }
  };

  // Button handlers use animated zoom for smooth transitions
  const handleZoomIn = () => setAnimatedZoomTarget(Math.min(zoom * 1.5, 5.0));
  const handleZoomOut = () => setAnimatedZoomTarget(Math.max(zoom / 1.5, minZoom));
  const handleMinZoomChange = useCallback((newMinZoom: number) => {
    setMinZoom(newMinZoom);
  }, []);
  const handleReset = () => {
    setAnimatedZoomTarget(1.0);
    setViewportTopY(0);
  };
  const handleAnimatedZoomComplete = useCallback(() => {
    setAnimatedZoomTarget(null);
  }, []);

  // F124: Navigation handlers for sidebar and timeline clicks
  const handleNavigateToTrain = useCallback((trainIndex: number) => {
    setNavigationTarget({ trainIndex });
  }, []);

  const handleNavigateToDate = useCallback((dayOffset: number) => {
    setNavigationTarget({ dayOffset });
  }, []);

  const handleNavigationComplete = useCallback(() => {
    setNavigationTarget(null);
  }, []);

  // F025: Minimap navigation - navigate to world coordinates
  const handleMinimapNavigate = useCallback((worldX: number, worldY: number) => {
    // Convert world coordinates to day offset and train index
    const dayOffset = worldX / pxPerDay;
    const trainIndex = -worldY / pxPerTrain; // Y is negative in world

    // Navigate to the position
    setNavigationTarget({
      dayOffset: Math.max(0, dayOffset),
      trainIndex: Math.max(0, Math.min(TRAIN_COUNT - 1, Math.round(trainIndex))),
    });
  }, []);

  // BUG-004: Removed handleMinimapToggle - minimap is now always visible (Google Maps style)

  const handleZoomChange = useCallback((newZoom: number) => {
    setZoom(newZoom);
    // Track zooming state for perf logging
    setIsZooming(true);
    // Reset zooming after brief delay
    const timeout = setTimeout(() => setIsZooming(false), 100);
    return () => clearTimeout(timeout);
  }, []);

  const handleViewportChange = useCallback((viewport: ViewportInfo) => {
    setViewportTopY(viewport.topY);
    setViewportLeftX(viewport.leftX);
    setViewportRightX(viewport.rightX);
    // Track panning state for perf logging
    setIsPanning(true);
    // Reset panning after brief delay
    const timeout = setTimeout(() => setIsPanning(false), 100);
    return () => clearTimeout(timeout);
  }, []);

  // Determine current performance event for logging
  const getCurrentPerfEvent = useCallback((): PerfEvent => {
    const currentLod = getLOD(zoom);
    if (prevLod.current !== currentLod) {
      prevLod.current = currentLod;
      return 'lod_transition';
    }
    if (animatedZoomTarget != null || navigationTarget != null) {
      return 'animating';
    }
    if (isZooming) return 'zooming';
    if (isPanning) return 'panning';
    return 'idle';
  }, [zoom, animatedZoomTarget, navigationTarget, isZooming, isPanning]);

  const perfEvent = getCurrentPerfEvent();

  // Calculate sidebar offset to align with canvas
  // viewportTopY = 0 means TRAIN-001 is at the top
  // viewportTopY = -24 means TRAIN-002 is at the top
  // Sidebar offset = -viewportTopY (positive value scrolls down)
  const rowHeight = pxPerTrain * zoom;
  const sidebarOffset = viewportTopY * zoom;

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
      {/* Navbar with app title and zoom controls */}
      <Navbar fixedToTop={false}>
        <NavbarGroup align={Alignment.LEFT}>
          <NavbarHeading>
            <strong>MMS</strong> Canvas
          </NavbarHeading>
          <NavbarDivider />
          <span style={{ fontFamily: 'monospace', fontSize: 13 }}>
            Zoom: {zoom.toFixed(2)}x
          </span>
          <NavbarDivider />
          <Tag intent={getLODIntent(lod)} minimal large>
            {lod}
          </Tag>
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <ButtonGroup minimal>
            <Button icon="minus" onClick={handleZoomOut} title="Zoom Out" />
            <Button icon="plus" onClick={handleZoomIn} title="Zoom In" />
          </ButtonGroup>
          <NavbarDivider />
          <Button icon="reset" minimal onClick={handleReset}>
            Reset View
          </Button>
          <NavbarDivider />
          <Button
            icon="dashboard"
            minimal
            active={perfVisible}
            onClick={togglePerf}
            title="Toggle Performance Monitor (P)"
          >
            Perf
          </Button>
        </NavbarGroup>
      </Navbar>

      {/* Timeline header - positioned above canvas, offset by sidebar width */}
      <TimelineHeader
        viewportLeftX={viewportLeftX}
        viewportRightX={viewportRightX}
        zoom={zoom}
        sidebarWidth={SIDEBAR_WIDTH}
        onDateClick={handleNavigateToDate}
      />

      {/* Main content area with sidebar and canvas */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden', minHeight: 0 }}>
        {/* Train sidebar using BlueprintJS Card */}
        <Card
          elevation={1}
          style={{
            width: SIDEBAR_WIDTH,
            borderRadius: 0,
            padding: 0,
            flexShrink: 0,
            display: 'flex',
            flexDirection: 'column',
            overflow: 'hidden',
          }}
        >
          {/* Sidebar header */}
          <div
            style={{
              padding: '10px 12px',
              borderBottom: '1px solid #e1e8ed',
              backgroundColor: '#f5f8fa',
              fontWeight: 600,
              fontSize: 13,
            }}
          >
            Trains
          </div>

          {/* Scrollable train list - synced with canvas panY (BUG-002 fix: overflow auto) */}
          <div
            style={{
              flex: 1,
              overflow: 'auto',
              position: 'relative',
            }}
          >
            <div
              style={{
                position: 'absolute',
                top: sidebarOffset,
                left: 0,
                right: 0,
              }}
            >
              {Array.from({ length: TRAIN_COUNT }, (_, i) => (
                <div
                  key={i}
                  onClick={() => handleNavigateToTrain(i)}
                  style={{
                    height: rowHeight,
                    padding: '0 12px',
                    fontSize: 12,
                    fontFamily: 'monospace',
                    display: 'flex',
                    alignItems: 'center',
                    borderBottom: '1px solid #f0f0f0',
                    backgroundColor: i % 2 === 0 ? '#ffffff' : '#fafafa',
                    cursor: 'pointer',
                    transition: 'background-color 0.15s ease',
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.backgroundColor = '#e1e8ed';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.backgroundColor = i % 2 === 0 ? '#ffffff' : '#fafafa';
                  }}
                  title={`Click to navigate to TRAIN-${String(i + 1).padStart(3, '0')}`}
                >
                  TRAIN-{String(i + 1).padStart(3, '0')}
                </div>
              ))}
            </div>
          </div>
        </Card>

        {/* Canvas area - deck.gl canvas (DECK-COMPLETE-001: R3F removed) */}
        <div
          style={{ flex: 1, position: 'relative', minWidth: 0 }}
          onMouseMove={(e) => setMousePos({ x: e.clientX, y: e.clientY })}
        >
          <DeckCanvas
            zoom={zoom}
            lod={lod}
            onZoomChange={handleZoomChange}
            onViewportChange={handleViewportChange}
            onMinZoomChange={handleMinZoomChange}
            animatedZoomTarget={animatedZoomTarget}
            onAnimatedZoomComplete={handleAnimatedZoomComplete}
            navigationTarget={navigationTarget}
            onNavigationComplete={handleNavigationComplete}
            perfVisible={perfVisible}
            perfEvent={perfEvent}
          />

          {/* Minimap (F025, BUG-004) - bird's eye navigation - always visible (Google Maps style) */}
          <Minimap
            trainCount={TRAIN_COUNT}
            totalDays={TOTAL_DAYS}
            tasks={tasks}
            cameraX={canvasCameraX}
            cameraY={canvasCameraY}
            zoom={zoom}
            canvasWidth={canvasSizeFromStore.width || 800}
            canvasHeight={canvasSizeFromStore.height || 600}
            onNavigate={handleMinimapNavigate}
          />
        </div>
      </div>

      {/* Task tooltip (F020) - shown on hover */}
      <TaskTooltip
        taskId={hoveredTaskId}
        mouseX={mousePos.x}
        mouseY={mousePos.y}
      />

      {/* Task details panel (F026) - shown on selection */}
      <TaskDetailsPanel />

      {/* Performance panel - reliable FPS monitor using stats.js */}
      {/* BUG-005: Moved to bottom-left to avoid overlapping TimelineHeader */}
      <PerformancePanel
        visible={perfVisible}
        position="bottom-left"
      />
    </div>
  );
}

export default App;

content.content:
     1→/**
     2→ * MicroLayer (deck.gl) - Detailed task card visualization
     3→ *
     4→ * Renders detailed task cards with labels at zoom > 2.0x (MICRO LOD level).
     5→ *
     6→ * Features:
     7→ * - SolidPolygonLayer for task cards and backgrounds
     8→ * - TextLayer for task labels
     9→ * - PathLayer for grid lines and dependency arrows
    10→ * - Viewport culling for performance
    11→ * - Hover/selection/focus highlighting
    12→ *
    13→ * DECK-MIGRATE-002: Replaces R3F MicroLayer
    14→ */
    15→
    16→import { SolidPolygonLayer, PathLayer, TextLayer } from '@deck.gl/layers';
    17→import type { Layer } from '@deck.gl/core';
    18→import type { TaskRender } from '../../data/types';
    19→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    20→
    21→// ─────────────────────────────────────────────────────────────
    22→// CONSTANTS
    23→// ─────────────────────────────────────────────────────────────
    24→
    25→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    26→
    27→// Task card dimensions
    28→const CARD_PADDING = 2;
    29→const CARD_HEIGHT = pxPerTrain - CARD_PADDING * 2 - 2;
    30→
    31→// Color palette (as RGBA)
    32→const COLORS: Record<string, [number, number, number, number]> = {
    33→  blue: [59, 130, 246, 255],
    34→  orange: [245, 158, 11, 255],
    35→  gray: [156, 163, 175, 255],
    36→};
    37→
    38→const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 255];
    39→const SELECTION_COLOR: [number, number, number, number] = [6, 182, 212, 255];
    40→const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 255];
    41→
    42→// Grid colors
    43→const GRID_COLOR_MAJOR: [number, number, number, number] = [209, 213, 219, 128];
    44→const GRID_COLOR_MINOR: [number, number, number, number] = [229, 231, 235, 102];
    45→
    46→// Row background colors
    47→const ROW_BG_EVEN: [number, number, number, number] = [255, 255, 255, 128];
    48→const ROW_BG_ODD: [number, number, number, number] = [248, 250, 252, 128];
    49→
    50→// Dependency line colors
    51→const DEPENDENCY_LINE_COLOR: [number, number, number, number] = [139, 92, 246, 204];
    52→
    53→// ─────────────────────────────────────────────────────────────
    54→// TYPES
    55→// ─────────────────────────────────────────────────────────────
    56→
    57→export interface ViewportBounds {
    58→  minX: number;
    59→  maxX: number;
    60→  minY: number;
    61→  maxY: number;
    62→}
    63→
    64→interface TaskPolygon {
    65→  id: string;
    66→  polygon: [number, number][];
    67→  task: TaskRender;
    68→}
    69→
    70→interface RowBackground {
    71→  trainIndex: number;
    72→  polygon: [number, number][];
    73→  isEven: boolean;
    74→}
    75→
    76→interface GridLine {
    77→  path: [number, number][];
    78→  isMajor: boolean;
    79→}
    80→
    81→interface TaskLabel {
    82→  position: [number, number];
    83→  text: string;
    84→  taskId: string;
    85→}
    86→
    87→interface DependencyPath {
    88→  path: [number, number][];
    89→  fromId: string;
    90→  toId: string;
    91→}
    92→
    93→interface EffectPolygon {
    94→  taskId: string;
    95→  polygon: [number, number][];
    96→}
    97→
    98→// ─────────────────────────────────────────────────────────────
    99→// HELPER FUNCTIONS
   100→// ─────────────────────────────────────────────────────────────
   101→
   102→function brightenColor(
   103→  color: [number, number, number, number],
   104→  factor: number
   105→): [number, number, number, number] {
   106→  return [
   107→    Math.min(255, Math.round(color[0] * factor)),
   108→    Math.min(255, Math.round(color[1] * factor)),
   109→    Math.min(255, Math.round(color[2] * factor)),
   110→    color[3],
   111→  ];
   112→}
   113→
   114→function applyOpacity(
   115→  color: [number, number, number, number],
   116→  opacity: number
   117→): [number, number, number, number] {
   118→  return [color[0], color[1], color[2], Math.round(color[3] * opacity)];
   119→}
   120→
   121→function createRectPolygon(
   122→  x1: number,
   123→  y1: number,
   124→  x2: number,
   125→  y2: number
   126→): [number, number][] {
   127→  return [
   128→    [x1, y1],
   129→    [x2, y1],
   130→    [x2, y2],
   131→    [x1, y2],
   132→    [x1, y1],
   133→  ];
   134→}
   135→
   136→/**
   137→ * Filter tasks visible within viewport bounds
   138→ */
   139→function filterVisibleTasks(
   140→  tasks: TaskRender[],
   141→  viewportBounds?: ViewportBounds
   142→): TaskRender[] {
   143→  if (!viewportBounds) return tasks;
   144→
   145→  const padding = 100;
   146→  const minX = viewportBounds.minX - padding;
   147→  const maxX = viewportBounds.maxX + padding;
   148→  const minY = viewportBounds.minY - padding;
   149→  const maxY = viewportBounds.maxY + padding;
   150→
   151→  return tasks.filter((task) => {
   152→    const taskStartX = task.startDay * pxPerDay;
   153→    const taskEndX = taskStartX + task.duration * pxPerDay;
   154→    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   155→
   156→    const xOverlap = taskEndX >= minX && taskStartX <= maxX;
   157→    const yOverlap = taskY + pxPerTrain / 2 >= minY && taskY - pxPerTrain / 2 <= maxY;
   158→
   159→    return xOverlap && yOverlap;
   160→  });
   161→}
   162→
   163→// ─────────────────────────────────────────────────────────────
   164→// DATA GENERATION
   165→// ─────────────────────────────────────────────────────────────
   166→
   167→function generateRowBackgrounds(
   168→  trainCount: number,
   169→  totalDays: number,
   170→  viewportBounds?: ViewportBounds
   171→): RowBackground[] {
   172→  const totalWidth = totalDays * pxPerDay;
   173→  const backgrounds: RowBackground[] = [];
   174→
   175→  // Calculate visible range
   176→  let minTrainIndex = 0;
   177→  let maxTrainIndex = trainCount - 1;
   178→
   179→  if (viewportBounds) {
   180→    minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   181→    maxTrainIndex = Math.min(trainCount - 1, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   182→  }
   183→
   184→  for (let i = minTrainIndex; i <= maxTrainIndex; i++) {
   185→    const y1 = -i * pxPerTrain;
   186→    const y2 = -(i + 1) * pxPerTrain;
   187→
   188→    backgrounds.push({
   189→      trainIndex: i,
   190→      polygon: createRectPolygon(0, y1, totalWidth, y2),
   191→      isEven: i % 2 === 0,
   192→    });
   193→  }
   194→
   195→  return backgrounds;
   196→}
   197→
   198→function generateGridLines(
   199→  totalDays: number,
   200→  trainCount: number,
   201→  viewportBounds?: ViewportBounds
   202→): { horizontal: GridLine[]; vertical: GridLine[] } {
   203→  const totalWidth = totalDays * pxPerDay;
   204→  const totalHeight = trainCount * pxPerTrain;
   205→
   206→  const horizontal: GridLine[] = [];
   207→  const vertical: GridLine[] = [];
   208→
   209→  // Visible horizontal lines (train boundaries)
   210→  let minTrainIndex = 0;
   211→  let maxTrainIndex = trainCount;
   212→
   213→  if (viewportBounds) {
   214→    minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   215→    maxTrainIndex = Math.min(trainCount, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   216→  }
   217→
   218→  for (let i = minTrainIndex; i <= maxTrainIndex; i++) {
   219→    const y = -i * pxPerTrain;
   220→    horizontal.push({
   221→      path: [[0, y], [totalWidth, y]],
   222→      isMajor: true,
   223→    });
   224→  }
   225→
   226→  // Visible vertical lines (week boundaries)
   227→  let minDay = 0;
   228→  let maxDay = totalDays;
   229→
   230→  if (viewportBounds) {
   231→    minDay = Math.max(0, Math.floor(viewportBounds.minX / pxPerDay / 7) * 7 - 7);
   232→    maxDay = Math.min(totalDays, Math.ceil(viewportBounds.maxX / pxPerDay / 7) * 7 + 7);
   233→  }
   234→
   235→  for (let day = minDay; day <= maxDay; day += 7) {
   236→    const x = day * pxPerDay;
   237→    const isMajor = day % 30 === 0;
   238→    vertical.push({
   239→      path: [[x, 0], [x, -totalHeight]],
   240→      isMajor,
   241→    });
   242→  }
   243→
   244→  return { horizontal, vertical };
   245→}
   246→
   247→function generateTaskPolygons(tasks: TaskRender[]): TaskPolygon[] {
   248→  return tasks.map((task) => {
   249→    const width = task.duration * pxPerDay - CARD_PADDING * 2;
   250→    const x1 = task.startDay * pxPerDay + CARD_PADDING;
   251→    const x2 = x1 + width;
   252→    const y1 = -task.trainIndex * pxPerTrain - CARD_PADDING;
   253→    const y2 = y1 - CARD_HEIGHT;
   254→
   255→    return {
   256→      id: task.id,
   257→      polygon: createRectPolygon(x1, y1, x2, y2),
   258→      task,
   259→    };
   260→  });
   261→}
   262→
   263→function generateTaskLabels(
   264→  tasks: TaskRender[],
   265→  linearZoom: number,
   266→  maxLabels: number = 50
   267→): TaskLabel[] {
   268→  // Only show labels on tasks wide enough
   269→  const minWidthForLabel = 40 / linearZoom;
   270→  const filtered = tasks.filter((t) => t.duration * pxPerDay > minWidthForLabel);
   271→
   272→  // Sort by width (largest first) and take top N
   273→  const sorted = filtered
   274→    .sort((a, b) => b.duration - a.duration)
   275→    .slice(0, maxLabels);
   276→
   277→  return sorted.map((task) => {
   278→    const width = task.duration * pxPerDay;
   279→    const x = task.startDay * pxPerDay + width / 2;
   280→    const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   281→    const label = task.type.charAt(0).toUpperCase() + task.type.slice(1);
   282→
   283→    return {
   284→      position: [x, y] as [number, number],
   285→      text: label,
   286→      taskId: task.id,
   287→    };
   288→  });
   289→}
   290→
   291→function generateConflictGlows(tasks: TaskRender[]): EffectPolygon[] {
   292→  return tasks
   293→    .filter((t) => t.hasConflict)
   294→    .map((task) => {
   295→      const padding = 2;
   296→      const width = task.duration * pxPerDay;
   297→      const x1 = task.startDay * pxPerDay - padding;
   298→      const x2 = x1 + width + padding * 2;
   299→      const y1 = -task.trainIndex * pxPerTrain - CARD_PADDING + padding;
   300→      const y2 = y1 - CARD_HEIGHT - padding * 2;
   301→
   302→      return {
   303→        taskId: task.id,
   304→        polygon: createRectPolygon(x1, y1, x2, y2),
   305→      };
   306→    });
   307→}
   308→
   309→function generateFocusRing(
   310→  tasks: TaskRender[],
   311→  focusedTaskId: string | null
   312→): EffectPolygon | null {
   313→  if (!focusedTaskId) return null;
   314→
   315→  const task = tasks.find((t) => t.id === focusedTaskId);
   316→  if (!task) return null;
   317→
   318→  const padding = 3;
   319→  const width = task.duration * pxPerDay;
   320→  const x1 = task.startDay * pxPerDay - padding;
   321→  const x2 = x1 + width + padding * 2;
   322→  const y1 = -task.trainIndex * pxPerTrain - CARD_PADDING + padding;
   323→  const y2 = y1 - CARD_HEIGHT - padding * 2;
   324→
   325→  return {
   326→    taskId: task.id,
   327→    polygon: createRectPolygon(x1, y1, x2, y2),
   328→  };
   329→}
   330→
   331→function generateDependencyPaths(tasks: TaskRender[]): DependencyPath[] {
   332→  const taskMap = new Map(tasks.map((t) => [t.id, t]));
   333→  const paths: DependencyPath[] = [];
   334→
   335→  for (const task of tasks) {
   336→    if (task.predecessorId) {
   337→      const predecessor = taskMap.get(task.predecessorId);
   338→      if (predecessor) {
   339→        // From: right edge of predecessor
   340→        const fromX = (predecessor.startDay + predecessor.duration) * pxPerDay;
   341→        const fromY = -predecessor.trainIndex * pxPerTrain - pxPerTrain / 2;
   342→
   343→        // To: left edge of dependent
   344→        const toX = task.startDay * pxPerDay;
   345→        const toY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   346→
   347→        const midX = (fromX + toX) / 2;
   348→        const isSameRow = predecessor.trainIndex === task.trainIndex;
   349→
   350→        let path: [number, number][];
   351→        if (isSameRow) {
   352→          const offsetY = 8;
   353→          path = [
   354→            [fromX, fromY + offsetY],
   355→            [midX, fromY + offsetY + 5],
   356→            [toX, toY + offsetY],
   357→          ];
   358→        } else {
   359→          const controlOffset = Math.abs(toY - fromY) * 0.3;
   360→          path = [
   361→            [fromX, fromY],
   362→            [fromX + controlOffset, fromY],
   363→            [midX, (fromY + toY) / 2],
   364→            [toX - controlOffset, toY],
   365→            [toX, toY],
   366→          ];
   367→        }
   368→
   369→        paths.push({
   370→          path,
   371→          fromId: predecessor.id,
   372→          toId: task.id,
   373→        });
   374→      }
   375→    }
   376→  }
   377→
   378→  return paths;
   379→}
   380→
   381→// ─────────────────────────────────────────────────────────────
   382→// LAYER FACTORY
   383→// ─────────────────────────────────────────────────────────────
   384→
   385→export interface MicroLayerOptions {
   386→  tasks: TaskRender[];
   387→  trainCount: number;
   388→  totalDays?: number;
   389→  visible?: boolean;
   390→  opacity?: number;
   391→  linearZoom?: number;
   392→  viewportBounds?: ViewportBounds;
   393→  hoveredTaskId?: string | null;
   394→  selectedTaskId?: string | null;
   395→  focusedTaskId?: string | null;
   396→}
   397→
   398→/**
   399→ * Create MicroLayer (deck.gl layers) for detailed task visualization
   400→ *
   401→ * Returns an array of layers:
   402→ * - Row backgrounds
   403→ * - Grid lines
   404→ * - Conflict glows
   405→ * - Focus ring
   406→ * - Task cards
   407→ * - Task labels
   408→ * - Dependency lines
   409→ */
   410→export function createMicroLayers({
   411→  tasks,
   412→  trainCount,
   413→  totalDays = 365 * 10,
   414→  visible = true,
   415→  opacity = 1,
   416→  linearZoom = 3,
   417→  viewportBounds,
   418→  hoveredTaskId = null,
   419→  selectedTaskId = null,
   420→  focusedTaskId = null,
   421→}: MicroLayerOptions): Layer[] {
   422→  if (!visible) {
   423→    return [];
   424→  }
   425→
   426→  // Don't render labels during low opacity transitions
   427→  const showLabels = opacity >= 0.3;
   428→
   429→  // Filter to visible tasks
   430→  const visibleTasks = filterVisibleTasks(tasks, viewportBounds);
   431→
   432→  // Generate data
   433→  const rowBackgrounds = generateRowBackgrounds(trainCount, totalDays, viewportBounds);
   434→  const { horizontal: hGridLines, vertical: vGridLines } = generateGridLines(
   435→    totalDays,
   436→    trainCount,
   437→    viewportBounds
   438→  );
   439→  const taskPolygons = generateTaskPolygons(visibleTasks);
   440→  const conflictGlows = generateConflictGlows(visibleTasks);
   441→  const focusRing = generateFocusRing(visibleTasks, focusedTaskId);
   442→  const taskLabels = showLabels ? generateTaskLabels(visibleTasks, linearZoom) : [];
   443→  const dependencyPaths = generateDependencyPaths(visibleTasks);
   444→
   445→  const layers: Layer[] = [];
   446→
   447→  // Layer 1: Row backgrounds (bottom)
   448→  layers.push(
   449→    new SolidPolygonLayer<RowBackground>({
   450→      id: 'micro-row-backgrounds',
   451→      data: rowBackgrounds,
   452→      getPolygon: (d) => d.polygon,
   453→      getFillColor: (d) =>
   454→        applyOpacity(d.isEven ? ROW_BG_EVEN : ROW_BG_ODD, opacity),
   455→      pickable: false,
   456→      updateTriggers: {
   457→        getFillColor: [opacity],
   458→      },
   459→    })
   460→  );
   461→
   462→  // Layer 2: Grid lines
   463→  if (hGridLines.length > 0 || vGridLines.length > 0) {
   464→    const allGridLines = [...hGridLines, ...vGridLines];
   465→    layers.push(
   466→      new PathLayer<GridLine>({
   467→        id: 'micro-grid-lines',
   468→        data: allGridLines,
   469→        getPath: (d) => d.path,
   470→        getColor: (d) =>
   471→          applyOpacity(d.isMajor ? GRID_COLOR_MAJOR : GRID_COLOR_MINOR, opacity),
   472→        getWidth: (d) => (d.isMajor ? 1.5 : 1),
   473→        widthUnits: 'pixels',
   474→        pickable: false,
   475→        updateTriggers: {
   476→          getColor: [opacity],
   477→        },
   478→      })
   479→    );
   480→  }
   481→
   482→  // Layer 3: Conflict glows
   483→  if (conflictGlows.length > 0) {
   484→    layers.push(
   485→      new SolidPolygonLayer<EffectPolygon>({
   486→        id: 'micro-conflict-glows',
   487→        data: conflictGlows,
   488→        getPolygon: (d) => d.polygon,
   489→        getFillColor: applyOpacity([239, 68, 68, 76], opacity),
   490→        pickable: false,
   491→        updateTriggers: {
   492→          getFillColor: [opacity],
   493→        },
   494→      })
   495→    );
   496→  }
   497→
   498→  // Layer 4: Focus ring
   499→  if (focusRing) {
   500→    layers.push(
   501→      new SolidPolygonLayer<EffectPolygon>({
   502→        id: 'micro-focus-ring',
   503→        data: [focusRing],
   504→        getPolygon: (d) => d.polygon,
   505→        getFillColor: applyOpacity([139, 92, 246, 102], opacity),
   506→        pickable: false,
   507→        updateTriggers: {
   508→          getFillColor: [opacity],
   509→        },
   510→      })
   511→    );
   512→  }
   513→
   514→  // Layer 5: Task cards (pickable)
   515→  layers.push(
   516→    new SolidPolygonLayer<TaskPolygon>({
   517→      id: 'micro-task-cards',
   518→      data: taskPolygons,
   519→      getPolygon: (d) => d.polygon,
   520→      getFillColor: (d) => {
   521→        const { task } = d;
   522→        const isSelected = task.id === selectedTaskId;
   523→        const isFocused = task.id === focusedTaskId;
   524→        const isHovered = task.id === hoveredTaskId;
   525→
   526→        let color: [number, number, number, number];
   527→
   528→        if (isSelected) {
   529→          color = SELECTION_COLOR;
   530→        } else if (isFocused) {
   531→          color = FOCUS_COLOR;
   532→        } else if (task.hasConflict) {
   533→          color = isHovered ? brightenColor(CONFLICT_COLOR, 1.3) : CONFLICT_COLOR;
   534→        } else {
   535→          const baseColor = COLORS[task.color] || COLORS.gray;
   536→          color = isHovered ? brightenColor(baseColor, 1.3) : baseColor;
   537→        }
   538→
   539→        return applyOpacity(color, opacity);
   540→      },
   541→      pickable: true,
   542→      updateTriggers: {
   543→        getFillColor: [opacity, hoveredTaskId, selectedTaskId, focusedTaskId],
   544→      },
   545→    })
   546→  );
   547→
   548→  // Layer 6: Task labels
   549→  if (taskLabels.length > 0) {
   550→    layers.push(
   551→      new TextLayer<TaskLabel>({
   552→        id: 'micro-task-labels',
   553→        data: taskLabels,
   554→        getPosition: (d) => d.position,
   555→        getText: (d) => d.text,
   556→        getSize: 10,
   557→        getColor: applyOpacity([255, 255, 255, 255], opacity),
   558→        getTextAnchor: 'middle',
   559→        getAlignmentBaseline: 'center',
   560→        fontFamily: 'system-ui, -apple-system, sans-serif',
   561→        fontWeight: 'bold',
   562→        pickable: false,
   563→        updateTriggers: {
   564→          getColor: [opacity],
   565→        },
   566→      })
   567→    );
   568→  }
   569→
   570→  // Layer 7: Dependency lines
   571→  if (dependencyPaths.length > 0 && opacity >= 0.3) {
   572→    layers.push(
   573→      new PathLayer<DependencyPath>({
   574→        id: 'micro-dependency-lines',
   575→        data: dependencyPaths,
   576→        getPath: (d) => d.path,
   577→        getColor: applyOpacity(DEPENDENCY_LINE_COLOR, opacity),
   578→        getWidth: 2,
   579→        widthUnits: 'pixels',
   580→        pickable: false,
   581→        updateTriggers: {
   582→          getColor: [opacity],
   583→        },
   584→      })
   585→    );
   586→  }
   587→
   588→  return layers;
   589→}
   590→
   591→/**
   592→ * Export constants for use in other modules
   593→ */
   594→export const MICRO_CONSTANTS = {
   595→  CARD_PADDING,
