     1→/**
     2→ * MacroLayer (deck.gl) - Strategic heatmap visualization
     3→ *
     4→ * Renders a heatmap showing task density across trains and time.
     5→ * Visible at zoom levels < 0.5x (MACRO LOD level).
     6→ *
     7→ * Features:
     8→ * - Aggregates tasks by month/train into cells
     9→ * - Color gradient: yellow (low) → orange (medium) → red (high density)
    10→ * - SolidPolygonLayer for optimal performance
    11→ * - Shows 10-20 year strategic overview
    12→ *
    13→ * DECK-MIGRATE-002: Replaces R3F InstancedMesh-based MacroLayer
    14→ */
    15→
    16→import { SolidPolygonLayer } from '@deck.gl/layers';
    17→import { interpolateYlOrRd } from 'd3-scale-chromatic';
    18→import type { TaskRender } from '../../data/types';
    19→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    20→
    21→// ─────────────────────────────────────────────────────────────
    22→// CONSTANTS
    23→// ─────────────────────────────────────────────────────────────
    24→
    25→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    26→
    27→// Heatmap cell size
    28→const DAYS_PER_CELL = 30; // ~1 month per cell
    29→const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
    30→const CELL_HEIGHT = pxPerTrain; // 24px per train row
    31→const CELL_GAP = 1; // Small gap between cells
    32→
    33→// Empty cell background color
    34→const EMPTY_CELL_COLOR: [number, number, number, number] = [248, 250, 252, 255]; // slate-50
    35→
    36→// ─────────────────────────────────────────────────────────────
    37→// TYPES
    38→// ─────────────────────────────────────────────────────────────
    39→
    40→interface HeatmapCell {
    41→  trainIndex: number;
    42→  monthIndex: number;
    43→  density: number;
    44→  polygon: [number, number][];
    45→  color: [number, number, number, number];
    46→}
    47→
    48→// ─────────────────────────────────────────────────────────────
    49→// COLOR FUNCTIONS
    50→// ─────────────────────────────────────────────────────────────
    51→
    52→/**
    53→ * Parse d3 color string (rgb or hex) to RGBA array
    54→ */
    55→function parseColorToRGBA(colorString: string): [number, number, number, number] {
    56→  // Handle rgb() format from d3
    57→  const rgbMatch = colorString.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
    58→  if (rgbMatch) {
    59→    return [
    60→      parseInt(rgbMatch[1]),
    61→      parseInt(rgbMatch[2]),
    62→      parseInt(rgbMatch[3]),
    63→      255,
    64→    ];
    65→  }
    66→
    67→  // Handle hex format
    68→  if (colorString.startsWith('#')) {
    69→    const hex = colorString.slice(1);
    70→    return [
    71→      parseInt(hex.slice(0, 2), 16),
    72→      parseInt(hex.slice(2, 4), 16),
    73→      parseInt(hex.slice(4, 6), 16),
    74→      255,
    75→    ];
    76→  }
    77→
    78→  // Fallback
    79→  return [128, 128, 128, 255];
    80→}
    81→
    82→/**
    83→ * Get heatmap color based on density (0+)
    84→ * Uses d3-scale-chromatic interpolateYlOrRd for color progression
    85→ */
    86→function getHeatmapColor(density: number): [number, number, number, number] {
    87→  // No tasks = light background
    88→  if (density === 0) {
    89→    return EMPTY_CELL_COLOR;
    90→  }
    91→
    92→  // Normalize density (0-1 range, with max around 8 tasks)
    93→  const normalizedDensity = Math.min(density / 8, 1);
    94→
    95→  // Use d3 YlOrRd scale (0 = yellow, 1 = red)
    96→  // Start at 0.1 to avoid very light yellow for low values
    97→  const t = 0.1 + normalizedDensity * 0.9;
    98→  const colorString = interpolateYlOrRd(t);
    99→
   100→  return parseColorToRGBA(colorString);
   101→}
   102→
   103→// ─────────────────────────────────────────────────────────────
   104→// AGGREGATION
   105→// ─────────────────────────────────────────────────────────────
   106→
   107→/**
   108→ * Calculate task density per cell and generate cell data for rendering
   109→ */
   110→function generateHeatmapCells(
   111→  tasks: TaskRender[],
   112→  trainCount: number,
   113→  totalYears: number
   114→): HeatmapCell[] {
   115→  const totalMonths = totalYears * 12;
   116→
   117→  // Initialize density grid with zeros
   118→  const densityGrid: number[][] = Array.from({ length: trainCount }, () =>
   119→    Array(totalMonths).fill(0)
   120→  );
   121→
   122→  // Count tasks in each cell
   123→  for (const task of tasks) {
   124→    // Calculate which month(s) this task spans
   125→    const startMonth = Math.floor(task.startDay / DAYS_PER_CELL);
   126→    const endMonth = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);
   127→
   128→    // Increment count for all months the task spans
   129→    for (let month = startMonth; month <= endMonth && month < totalMonths; month++) {
   130→      if (month >= 0 && task.trainIndex >= 0 && task.trainIndex < trainCount) {
   131→        densityGrid[task.trainIndex][month]++;
   132→      }
   133→    }
   134→  }
   135→
   136→  // Generate cell data for SolidPolygonLayer
   137→  const cells: HeatmapCell[] = [];
   138→
   139→  for (let trainIndex = 0; trainIndex < trainCount; trainIndex++) {
   140→    for (let monthIndex = 0; monthIndex < totalMonths; monthIndex++) {
   141→      const density = densityGrid[trainIndex][monthIndex];
   142→
   143→      // Calculate cell bounds in world coordinates
   144→      // X: time axis (positive = future)
   145→      // Y: train axis (negative = down, TRAIN-001 at y=0)
   146→      const x1 = monthIndex * CELL_WIDTH + CELL_GAP / 2;
   147→      const x2 = (monthIndex + 1) * CELL_WIDTH - CELL_GAP / 2;
   148→      const y1 = -trainIndex * CELL_HEIGHT - CELL_GAP / 2;
   149→      const y2 = -(trainIndex + 1) * CELL_HEIGHT + CELL_GAP / 2;
   150→
   151→      // Create closed polygon [x1,y1] → [x2,y1] → [x2,y2] → [x1,y2] → [x1,y1]
   152→      const polygon: [number, number][] = [
   153→        [x1, y1],
   154→        [x2, y1],
   155→        [x2, y2],
   156→        [x1, y2],
   157→        [x1, y1], // Close the polygon
   158→      ];
   159→
   160→      cells.push({
   161→        trainIndex,
   162→        monthIndex,
