/**
 * MacroLayer (deck.gl) - Strategic heatmap visualization
 *
 * Renders a heatmap showing task density across trains and time.
 * Visible at zoom levels < 0.5x (MACRO LOD level).
 *
 * Features:
 * - Aggregates tasks by month/train into cells
 * - Color gradient: yellow (low) → orange (medium) → red (high density)
 * - SolidPolygonLayer for optimal performance
 * - Shows 10-20 year strategic overview
 *
 * DECK-MIGRATE-002: Replaces R3F InstancedMesh-based MacroLayer
 */

import { SolidPolygonLayer } from '@deck.gl/layers';
import { interpolateYlOrRd } from 'd3-scale-chromatic';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Heatmap cell size
const DAYS_PER_CELL = 30; // ~1 month per cell
const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px per train row
const CELL_GAP = 1; // Small gap between cells

// Empty cell background color
const EMPTY_CELL_COLOR: [number, number, number, number] = [248, 250, 252, 255]; // slate-50

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

interface HeatmapCell {
  trainIndex: number;
  monthIndex: number;
  density: number;
  polygon: [number, number][];
  color: [number, number, number, number];
}

// ─────────────────────────────────────────────────────────────
// COLOR FUNCTIONS
// ─────────────────────────────────────────────────────────────

/**
 * Parse d3 color string (rgb or hex) to RGBA array
 */
function parseColorToRGBA(colorString: string): [number, number, number, number] {
  // Handle rgb() format from d3
  const rgbMatch = colorString.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
  if (rgbMatch) {
    return [
      parseInt(rgbMatch[1]),
      parseInt(rgbMatch[2]),
      parseInt(rgbMatch[3]),
      255,
    ];
  }

  // Handle hex format
  if (colorString.startsWith('#')) {
    const hex = colorString.slice(1);
    return [
      parseInt(hex.slice(0, 2), 16),
      parseInt(hex.slice(2, 4), 16),
      parseInt(hex.slice(4, 6), 16),
      255,
    ];
  }

  // Fallback
  return [128, 128, 128, 255];
}

/**
 * Get heatmap color based on density (0+)
 * Uses d3-scale-chromatic interpolateYlOrRd for color progression
 */
function getHeatmapColor(density: number): [number, number, number, number] {
  // No tasks = light background
  if (density === 0) {
    return EMPTY_CELL_COLOR;
  }

  // Normalize density (0-1 range, with max around 8 tasks)
  const normalizedDensity = Math.min(density / 8, 1);

  // Use d3 YlOrRd scale (0 = yellow, 1 = red)
  // Start at 0.1 to avoid very light yellow for low values
  const t = 0.1 + normalizedDensity * 0.9;
  const colorString = interpolateYlOrRd(t);

  return parseColorToRGBA(colorString);
}

// ─────────────────────────────────────────────────────────────
// AGGREGATION
// ─────────────────────────────────────────────────────────────

/**
 * Calculate task density per cell and generate cell data for rendering
 */
function generateHeatmapCells(
  tasks: TaskRender[],
  trainCount: number,
  totalYears: number
): HeatmapCell[] {
  const totalMonths = totalYears * 12;

  // Initialize density grid with zeros
  const densityGrid: number[][] = Array.from({ length: trainCount }, () =>
    Array(totalMonths).fill(0)
  );

  // Count tasks in each cell
  for (const task of tasks) {
    // Calculate which month(s) this task spans
    const startMonth = Math.floor(task.startDay / DAYS_PER_CELL);
    const endMonth = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);

    // Increment count for all months the task spans
    for (let month = startMonth; month <= endMonth && month < totalMonths; month++) {
      if (month >= 0 && task.trainIndex >= 0 && task.trainIndex < trainCount) {
        densityGrid[task.trainIndex][month]++;
      }
    }
  }

  // Generate cell data for SolidPolygonLayer
  const cells: HeatmapCell[] = [];

  for (let trainIndex = 0; trainIndex < trainCount; trainIndex++) {
    for (let monthIndex = 0; monthIndex < totalMonths; monthIndex++) {
      const density = densityGrid[trainIndex][monthIndex];

      // Calculate cell bounds in world coordinates
      // X: time axis (positive = future)
      // Y: train axis (negative = down, TRAIN-001 at y=0)
      const x1 = monthIndex * CELL_WIDTH + CELL_GAP / 2;
      const x2 = (monthIndex + 1) * CELL_WIDTH - CELL_GAP / 2;
      const y1 = -trainIndex * CELL_HEIGHT - CELL_GAP / 2;
      const y2 = -(trainIndex + 1) * CELL_HEIGHT + CELL_GAP / 2;

      // Create closed polygon [x1,y1] → [x2,y1] → [x2,y2] → [x1,y2] → [x1,y1]
      const polygon: [number, number][] = [
        [x1, y1],
        [x2, y1],
        [x2, y2],
        [x1, y2],
        [x1, y1], // Close the polygon
      ];

      cells.push({
        trainIndex,
        monthIndex,
        density,
        polygon,
        color: getHeatmapColor(density),
      });
    }
  }

  return cells;
}

// ─────────────────────────────────────────────────────────────
// YEAR MARKERS
// ─────────────────────────────────────────────────────────────

interface YearMarker {
  year: number;
  polygon: [number, number][];
}

/**
 * Generate year marker lines (vertical lines at year boundaries)
 */
function generateYearMarkers(totalYears: number, trainCount: number): YearMarker[] {
  const totalHeight = trainCount * CELL_HEIGHT;
  const markers: YearMarker[] = [];

  for (let year = 0; year <= totalYears; year++) {
    const x = year * 12 * CELL_WIDTH;
    const lineWidth = 2;

    // Vertical line as thin polygon
    markers.push({
      year,
      polygon: [
        [x - lineWidth / 2, 0],
        [x + lineWidth / 2, 0],
        [x + lineWidth / 2, -totalHeight],
        [x - lineWidth / 2, -totalHeight],
        [x - lineWidth / 2, 0],
      ],
    });
  }

  return markers;
}

// ─────────────────────────────────────────────────────────────
// LAYER FACTORY
// ─────────────────────────────────────────────────────────────

export interface MacroLayerOptions {
  tasks: TaskRender[];
  trainCount: number;
  totalYears?: number;
  visible?: boolean;
  opacity?: number;
}

/**
 * Create MacroLayer (deck.gl SolidPolygonLayer) for heatmap visualization
 *
 * Returns an array of layers:
 * - Heatmap cells layer
 * - Year markers layer
 */
export function createMacroLayers({
  tasks,
  trainCount,
  totalYears = 10,
  visible = true,
  opacity = 1,
}: MacroLayerOptions): SolidPolygonLayer[] {
  if (!visible) {
    return [];
  }

  // Generate cell data
  const cells = generateHeatmapCells(tasks, trainCount, totalYears);
  const yearMarkers = generateYearMarkers(totalYears, trainCount);

  // Create heatmap cells layer
  const heatmapLayer = new SolidPolygonLayer<HeatmapCell>({
    id: 'macro-heatmap',
    data: cells,
    getPolygon: (d) => d.polygon,
    getFillColor: (d) => {
      // Apply opacity to alpha channel
      const [r, g, b, a] = d.color;
      return [r, g, b, Math.round(a * opacity)];
    },
    pickable: false, // Heatmap cells not individually pickable
    extruded: false,
    // Update when opacity changes
    updateTriggers: {
      getFillColor: [opacity],
    },
  });

  // Create year markers layer
  const yearMarkersLayer = new SolidPolygonLayer<YearMarker>({
    id: 'macro-year-markers',
    data: yearMarkers,
    getPolygon: (d) => d.polygon,
    getFillColor: [148, 163, 184, Math.round(76 * opacity)], // slate-400 at 30% opacity
    pickable: false,
    extruded: false,
    updateTriggers: {
      getFillColor: [opacity],
    },
  });

  return [heatmapLayer, yearMarkersLayer];
}

/**
 * Export constants for use in other modules
 */
export const MACRO_CONSTANTS = {
  DAYS_PER_CELL,
  CELL_WIDTH,
  CELL_HEIGHT,
  CELL_GAP,
};

/**
 * MMS Data Types
 *
 * Architecture: Persistence vs Rendering
 *
 * Data flows through two distinct layers:
 *
 * Persistent (JSON/API) → Runtime (in memory) → Rendering (canvas)
 *   startDate: string      (Date objects)       startDay: 74
 *   "2024-03-15"           for logic            trainIndex: 5
 *
 * Why this separation?
 * - Date objects cannot be serialized to JSON (become {})
 * - Canvas needs numeric offsets for position calculations
 * - Domain logic needs semantic dates for business rules
 */

import { extent, max } from 'd3-array';

// ─────────────────────────────────────────────────────────────
// ENUMS & CONSTANTS
// ─────────────────────────────────────────────────────────────

export type AssetType = 'ALSTOM' | 'KINKI';
export type TaskType = 'maintenance' | 'overhaul' | 'inspection';
export type MaintenanceLevel = 'A' | 'B' | 'C' | 'D';

// ─────────────────────────────────────────────────────────────
// DOMAIN TYPES (Persistent/Serializable)
// These types can be saved to JSON, sent via API, or stored in localStorage.
// ─────────────────────────────────────────────────────────────

export interface Train {
  id: string;              // "TRAIN-001" or "ALT-001"
  name: string;            // Display name
  assetType: AssetType;    // Fleet type
}

export interface Task {
  id: string;              // Unique identifier
  trainId: string;         // Reference to Train.id
  startDate: string;       // ISO 8601 date: "2024-03-15"
  endDate: string;         // ISO 8601 date: "2024-03-20"
  type: TaskType;          // Visual category
  hasConflict: boolean;    // Conflict indicator
  predecessorId?: string;  // Optional: ID of task that must complete before this one (F023)
}

export interface DatasetMeta {
  startDate: string;       // ISO 8601: "2024-01-01"
  trainCount: number;      // Number of trains
  years: number;           // Time range in years
}

export interface GeneratedData {
  trains: Train[];
  tasks: Task[];
  meta: DatasetMeta;
}

// ─────────────────────────────────────────────────────────────
// RENDERING TYPES (Runtime/Calculated)
// These types are computed when data loads and used by the canvas.
// Never persisted.
// ─────────────────────────────────────────────────────────────

export type TaskColor = 'blue' | 'orange' | 'gray';

export interface TaskRender {
  id: string;              // Same as Task.id
  trainIndex: number;      // Y position (0-based index in trains array)
  startDay: number;        // X position (days since meta.startDate)
  duration: number;        // Width (days)
  color: TaskColor;        // Derived from Task.type
  hasConflict: boolean;    // Passthrough from Task
  type: TaskType;          // For label display in MicroLayer
  predecessorId?: string;  // Optional: ID of predecessor task (F023)
}

export const TYPE_TO_COLOR: Record<TaskType, TaskColor> = {
  maintenance: 'blue',
  overhaul: 'orange',
  inspection: 'gray',
};

// ─────────────────────────────────────────────────────────────
// WORLD BOUNDS (Navigation limits)
// ─────────────────────────────────────────────────────────────

/**
 * Defines the navigable world boundaries.
 * Camera will be clamped to these bounds.
 *
 * Coordinate system:
 * - X: 0 = first day, positive = future
 * - Y: 0 = top (TRAIN-001), negative = down (more trains)
 */
export interface WorldBounds {
  minX: number;  // 0 (first day)
  maxX: number;  // totalDays * pxPerDay
  minY: number;  // -trainCount * pxPerTrain (bottom)
  maxY: number;  // 0 (top)
}

// ─────────────────────────────────────────────────────────────
// CANVAS CONFIGURATION
// ─────────────────────────────────────────────────────────────

export interface ViewConfig {
  pxPerDay: number;        // Pixels per day (X scale)
  pxPerTrain: number;      // Pixels per train row (Y scale)
  minZoom: number;         // Minimum zoom level
  maxZoom: number;         // Maximum zoom level
  zoomSensitivity: number; // Scroll sensitivity
  lodThresholds: {
    macro: number;         // Below this → MACRO view
    micro: number;         // Above this → MICRO view
  };
}

export type LODLevel = 'MACRO' | 'MESO' | 'MICRO';

export interface ViewportState {
  zoom: number;
  panX: number;
  panY: number;
  lod: LODLevel;
}

// ─────────────────────────────────────────────────────────────
// DEFAULT VALUES
// ─────────────────────────────────────────────────────────────

export const DEFAULT_VIEW_CONFIG: ViewConfig = {
  pxPerDay: 10,
  pxPerTrain: 24,
  minZoom: 0.1,
  maxZoom: 5,
  zoomSensitivity: 0.002,
  lodThresholds: {
    macro: 0.5,
    micro: 2.0,
  },
};

export const DEFAULT_DATASET_META: DatasetMeta = {
  startDate: '2024-01-01',
  trainCount: 50,
  years: 10,
};

