/**
 * POC: deck.gl Heatmap for Strategic View
 *
 * Demonstrates WebGL-accelerated rendering of a heatmap grid
 * showing maintenance utilization across 128 trains × 48 quarters (12 years).
 *
 * This POC validates:
 * 1. deck.gl integration with React
 * 2. Performance with 6,144+ cells
 * 3. Color interpolation for utilization visualization
 * 4. Hover interaction for cell tooltips
 */

import React, { useState, useMemo, useCallback } from 'react';
import type { Meta, StoryObj } from '@storybook/react';
import DeckGL from '@deck.gl/react';
import { OrthographicView } from '@deck.gl/core';
import { SolidPolygonLayer } from '@deck.gl/layers';
import { Card, Tag, Intent, Divider, Button, ButtonGroup, Slider } from '@blueprintjs/core';

import { generateMockData, type AggregatedCell } from '../../data/mock-generator';
import { COLORS, TOTAL_TRAINS, TIME_RANGE } from '../../data/mock-config';

// =============================================================================
// TYPES
// =============================================================================

interface TooltipInfo {
  x: number;
  y: number;
  cell: AggregatedCell | null;
}

interface ViewState {
  target: [number, number];
  zoom: number;
}

// =============================================================================
// CONSTANTS
// =============================================================================

const CELL_WIDTH = 30; // pixels per quarter
const CELL_HEIGHT = 8; // pixels per train
const GRID_WIDTH = TIME_RANGE.quarters * CELL_WIDTH; // 48 * 30 = 1440
const GRID_HEIGHT = TOTAL_TRAINS * CELL_HEIGHT; // 128 * 8 = 1024

// Color interpolation thresholds
const UTILIZATION_THRESHOLDS = {
  low: 20,
  medium: 50,
  high: 80,
};

// =============================================================================
// COLOR UTILITIES
// =============================================================================

function hexToRgb(hex: string): [number, number, number] {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result
    ? [
        parseInt(result[1], 16),
        parseInt(result[2], 16),
        parseInt(result[3], 16),
      ]
    : [128, 128, 128];
}

function interpolateColor(
  color1: [number, number, number],
  color2: [number, number, number],
  t: number
): [number, number, number, number] {
  return [
    Math.round(color1[0] + (color2[0] - color1[0]) * t),
    Math.round(color1[1] + (color2[1] - color1[1]) * t),
    Math.round(color1[2] + (color2[2] - color1[2]) * t),
    255,
  ];
}

function getUtilizationColor(utilization: number, hasOverhaul: boolean): [number, number, number, number] {
  // Overhaul cells get special color
  if (hasOverhaul) {
    return [251, 146, 60, 255]; // orange-400
  }

  const low = hexToRgb(COLORS.heatmap.low);
  const medium = hexToRgb(COLORS.heatmap.medium);
  const high = hexToRgb(COLORS.heatmap.high);
  const critical = hexToRgb(COLORS.heatmap.critical);

  if (utilization < UTILIZATION_THRESHOLDS.low) {
    const t = utilization / UTILIZATION_THRESHOLDS.low;
    return interpolateColor(low, medium, t);
  } else if (utilization < UTILIZATION_THRESHOLDS.medium) {
    const t = (utilization - UTILIZATION_THRESHOLDS.low) /
      (UTILIZATION_THRESHOLDS.medium - UTILIZATION_THRESHOLDS.low);
    return interpolateColor(medium, high, t);

